// Configuration for query security policies
case class QuerySecurityConfig(
  allowedDatabases: Set[String] = Set("analytics_db", "reporting_db"),
  allowedTables: Set[String] = Set.empty, // empty means check at database level
  deniedTables: Set[String] = Set("user_credentials", "api_keys", "internal_config", "audit_log_sensitive"),
  maxResultRows: Int = 100000,
  queryTimeoutSeconds: Int = 300,
  allowDDL: Boolean = false,
  allowDML: Boolean = false,
  allowedOperations: Set[String] = Set("SELECT"),
  maxQueryLengthChars: Int = 10000,
  deniedKeywords: Set[String] = Set(
    "INSERT", "UPDATE", "DELETE", "DROP", "CREATE", "ALTER", "TRUNCATE",
    "GRANT", "REVOKE", "EXEC", "EXECUTE", "CALL", "MERGE",
    "INTO OUTFILE", "INTO DUMPFILE", "LOAD_FILE", "LOAD DATA",
    "INFORMATION_SCHEMA", "SYS.", "SYSTEM.",
    "SET ", "RESET", "ADD JAR", "ADD FILE",
    "CREATE TEMPORARY FUNCTION", "CREATE FUNCTION",
    "UNCACHE", "CACHE", "REFRESH", "MSCK"
  )
)

// Result wrapper
sealed trait QueryResult
case class QuerySuccess(data: DataFrame, rowCount: Long, executionTimeMs: Long) extends QueryResult
